flow.set('sensorData', msg.payload);

var hr   = msg.payload.heartRate;
var dist = msg.payload.dist;
var sos  = msg.payload.sos;
var isEmergency = (hr > 120 && dist < 15) || sos === true;

if (isEmergency) {
  var lastAlert = flow.get('lastAlert') || 0;
  var now = Date.now();
  if (now - lastAlert > 60000) {
    flow.set('lastAlert', now);
    msg.emergency = true;
  }
}
return msg;

if (!msg.emergency) return null;

var accountSid = 'YOUR_ACCOUNT_SID';
var authToken  = 'YOUR_AUTH_TOKEN';
var from = 'whatsapp:+14155238886';
var to   = 'whatsapp:+91XXXXXXXXXX';

var body = '🚨 NEUROVIGILX EMERGENCY!\n'
  + 'Heart Rate: ' + msg.payload.heartRate + ' bpm\n'
  + 'Distance: '   + msg.payload.dist + ' cm\n'
  + 'SOS Button: ' + (msg.payload.sos ? 'YES' : 'NO') + '\n'
  + 'Location: '   + msg.payload.lat + '\n'
  + 'Time: '       + new Date().toLocaleString();

msg.url     = 'https://api.twilio.com/2010-04-01/Accounts/' + accountSid + '/Messages.json';
msg.method  = 'POST';
msg.payload = 'From=' + encodeURIComponent(from)
  + '&To='   + encodeURIComponent(to)
  + '&Body=' + encodeURIComponent(body);
msg.headers = {
  'Content-Type': 'application/x-www-form-urlencoded',
  'Authorization': 'Basic ' + Buffer.from(accountSid + ':' + authToken).toString('base64')
};
return msg;

var data = flow.get('sensorData') || {heartRate:0,lat:0,dist:0,sos:false};
msg.payload = data;
msg.statusCode = 200;
msg.headers = {'Content-Type':'application/json','Access-Control-Allow-Origin':'*'};
return msg;
